"use client";

export default function TornadoMascot() {
  // Pure SVG + CSS classes defined in globals.css
  return (
    <div className="mascot-wrap" aria-hidden="true">
      <svg
        className="mascot-svg"
        viewBox="0 0 200 200"
        role="img"
        aria-label="Chaotic Instinct Tornado Mascot"
      >
        <defs>
          <linearGradient id="twirl" x1="0" y1="0" x2="1" y2="1">
            <stop offset="0%" stopColor="rgba(255,255,255,0.9)" />
            <stop offset="100%" stopColor="rgba(255,255,255,0.2)" />
          </linearGradient>
          <filter id="softGlow">
            <feGaussianBlur stdDeviation="2" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>

        {/* Eyes */}
        <circle cx="85" cy="75" r="6" fill="white" />
        <circle cx="115" cy="75" r="6" fill="white" />
        <circle cx="85" cy="75" r="2.5" fill="#111827" />
        <circle cx="115" cy="75" r="2.5" fill="#111827" />

        {/* Mouth */}
        <path d="M80 92 Q100 100 120 92" stroke="white" strokeWidth="2" fill="none" opacity="0.8" />

        {/* Swirling rings */}
        <g filter="url(#softGlow)" stroke="url(#twirl)" strokeWidth="3" fill="none">
          <ellipse className="ring ring-1" cx="100" cy="60" rx="45" ry="12" />
          <ellipse className="ring ring-2" cx="100" cy="85" rx="55" ry="14" />
          <ellipse className="ring ring-3" cx="100" cy="110" rx="65" ry="16" />
          <ellipse className="ring ring-4" cx="100" cy="135" rx="50" ry="12" />
          <ellipse className="ring ring-5" cx="100" cy="155" rx="35" ry="9" />
        </g>

        {/* Little swirl particles */}
        <g className="specks">
          <circle cx="40" cy="50" r="1.5" fill="white" />
          <circle cx="160" cy="70" r="1.5" fill="white" />
          <circle cx="60" cy="140" r="1.5" fill="white" />
          <circle cx="150" cy="120" r="1.5" fill="white" />
        </g>
      </svg>
    </div>
  );
}
