"use client";

import { useEffect, useMemo, useState } from "react";

type Variant =
  | "default"
  | "architect"
  | "grow"
  | "security"
  | "fact"
  | "stock"
  | "crypto"
  | "vigilante"
  | "scrapsmith"
  | "ideatank";

const variantBubbles: Record<Variant, string[]> = {
  default: ["Check out Programs", "Explore the Forge"],
  architect: ["System Architect → tidy chaos", "Blueprints, hard-hat on."],
  grow: ["Grow Engine → optimize space", "Light • medium • yield"],
  security: ["Crystal‑Lock secures all apps", "Keys per user. Period."],
  fact: ["Truth graphs, sources, signals", "Verify before you amplify"],
  stock: ["Stock Surfer (paper mode)", "Learn by sim. Risk smart"],
  crypto: ["Crypto cockpit + alerts", "Unified risk, one view"],
  vigilante: ["Affiliate flows, rebates", "White‑label widgets"],
  scrapsmith: ["Build from what you own", "Harvest parts • blueprint"],
  ideatank: ["IdeaTank contests", "Submit & vote"],
};

export default function Mascot({
  variant = "default",
  className = "",
}: {
  variant?: Variant;
  className?: string;
}) {
  const bubbles = useMemo(() => variantBubbles[variant] ?? variantBubbles.default, [variant]);

  const [idx, setIdx] = useState(0);
  useEffect(() => {
    const id = setInterval(() => setIdx((i) => (i + 1) % bubbles.length), 3500);
    return () => clearInterval(id);
  }, [bubbles.length]);

  // simple accessories per variant
  const accessory = (v: Variant) => {
    switch (v) {
      case "architect":
        return (
          <>
            {/* hard hat */}
            <path d="M58 42 h44 v8 q-22 -10 -44 0 z" fill="#fbbf24" stroke="#f59e0b" strokeWidth="1.5" />
            {/* rolled blueprint */}
            <rect x="108" y="98" width="18" height="6" rx="3" fill="#60a5fa" />
          </>
        );
      case "grow":
        return (
          <>
            {/* little plant */}
            <path d="M100 120 q-4 -10 0 -18" stroke="#10b981" strokeWidth="2" />
            <path d="M96 104 q6 -6 12 0" stroke="#10b981" strokeWidth="2" />
            <circle cx="100" cy="122" r="2" fill="#10b981" />
            {/* farmer hat */}
            <path d="M56 44 h48 v7 q-24 -8 -48 0 z" fill="#d4a373" stroke="#b08968" strokeWidth="1.5" />
          </>
        );
      case "security":
        return (
          <>
            {/* badge */}
            <path d="M118 78 l6 6 -6 6 -6 -6 6 -6" fill="#60a5fa" />
          </>
        );
      case "fact":
        return <circle cx="124" cy="86" r="5" fill="#eab308" />; // magnifier hint
      case "stock":
        return (
          <>
            {/* up arrow */}
            <path d="M40 120 l20 -20 l12 12 l16 -16" stroke="#34d399" strokeWidth="3" fill="none" />
            <path d="M88 96 l0 -12 l12 0" stroke="#34d399" strokeWidth="3" fill="none" />
          </>
        );
      case "crypto":
        return <path d="M120 96 l6 10 l-6 10 l-6 -10 z" fill="#a78bfa" />; // diamond-ish
      case "vigilante":
        return <path d="M46 92 h20 l6 10 h-26 z" fill="#f472b6" />; // cape vibe
      case "scrapsmith":
        return <rect x="112" y="98" width="12" height="12" fill="#9ca3af" />; // tool block
      case "ideatank":
        return <circle cx="120" cy="76" r="6" fill="#f59e0b" />; // lightbulb node
      default:
        return null;
    }
  };

  return (
    <div className={`relative mascot-wrap ${className}`} aria-hidden="true">
      {/* Chat bubbles */}
      <div className="mascot-bubbles">
        <div className="bubble">{bubbles[idx]}</div>
      </div>

      {/* Tornado with permanent tie */}
      <svg className="mascot-svg" viewBox="0 0 160 160" role="img" aria-label="Tornado mascot">
        <defs>
          <linearGradient id="twirl" x1="0" y1="0" x2="1" y2="1">
            <stop offset="0%" stopColor="rgba(255,255,255,0.95)" />
            <stop offset="100%" stopColor="rgba(255,255,255,0.35)" />
          </linearGradient>
          <filter id="softGlow">
            <feGaussianBlur stdDeviation="1.4" result="b" />
            <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter>
        </defs>

        {/* face */}
        <circle cx="68" cy="58" r="5.5" fill="white" />
        <circle cx="92" cy="58" r="5.5" fill="white" />
        <circle cx="68" cy="58" r="2.2" fill="#0f1113" />
        <circle cx="92" cy="58" r="2.2" fill="#0f1113" />
        <path d="M66 72 Q80 78 94 72" stroke="white" strokeWidth="2" fill="none" opacity="0.85" vectorEffect="non-scaling-stroke"/>

        {/* tie (always on) */}
