"use client";

import { useEffect, useMemo, useState } from "react";

type Variant =
  | "default" | "architect" | "grow" | "security" | "fact"
  | "stock" | "crypto" | "vigilante" | "scrapsmith" | "ideatank";

const variantHints: Record<Variant, string[]> = {
  default: ["Hover a card to learn more.", "Tip: Programs → all tools in one place."],
  architect: ["System Architect: order that grows with you.", "Blueprints, hard-hat on."],
  grow: ["Grow Engine: optimize space, light, yield.", "Dial in parameters, see outcomes."],
  security: ["Crystal‑Lock: per-user keys across apps.", "Zero trust by design."],
  fact: ["Fact Correlation: sources, signals, graph.", "Verify before you amplify."],
  stock: ["Stock Surfer: paper trade, learn risk.", "Then graduate with caution."],
  crypto: ["Crypto cockpit: alerts + unified view.", "One risk model, two worlds."],
  vigilante: ["Vigilante: white‑label affiliate flows.", "Links, rebates, ledgers, widgets."],
  scrapsmith: ["ScrapSmith: build from what you own.", "Inventory → harvest → blueprint."],
  ideatank: ["IdeaTank: submit, vote, collaborate.", "Contests and blueprints."],
};

/** Simple event bus so any element can hint the mascot:
 * window.dispatchEvent(new CustomEvent('mascot:hint', { detail: { text: 'message', variant: 'grow' } }))
 */
export default function Mascot({ variant = "default" }: { variant?: Variant }) {
  const defaultMsgs = useMemo(() => variantHints[variant] ?? variantHints.default, [variant]);
  const [msgs, setMsgs] = useState<string[]>(defaultMsgs);
  const [idx, setIdx] = useState(0);

  useEffect(() => {
    const onHint = (e: Event) => {
      const ce = e as CustomEvent<{ text?: string; variant?: Variant }>;
      const v = ce.detail?.variant ?? variant;
      const list = ce.detail?.text ? [ce.detail.text, ...(variantHints[v] ?? variantHints.default)] : (variantHints[v] ?? variantHints.default);
      setMsgs(list);
      setIdx(0);
    };
    window.addEventListener("mascot:hint", onHint as EventListener);
    return () => window.removeEventListener("mascot:hint", onHint as EventListener);
  }, [variant]);

  useEffect(() => {
    const id = setInterval(() => setIdx((i) => (i + 1) % msgs.length), 3600);
    return () => clearInterval(id);
  }, [msgs]);

  const accessory = (v: Variant) => {
    switch (v) {
      case "architect":
        return (<>
          <path d="M58 42 h44 v8 q-22 -10 -44 0 z" fill="#fbbf24" stroke="#f59e0b" strokeWidth="1.5" />
          <rect x="108" y="98" width="18" height="6" rx="3" fill="#60a5fa" />
        </>);
      case "grow":
        return (<>
          <path d="M100 120 q-4 -10 0 -18" stroke="#10b981" strokeWidth="2" />
          <path d="M96 104 q6 -6 12 0" stroke="#10b981" strokeWidth="2" />
          <circle cx="100" cy="122" r="2" fill="#10b981" />
          <path d="M56 44 h48 v7 q-24 -8 -48 0 z" fill="#d4a373" stroke="#b08968" strokeWidth="1.5" />
        </>);
      case "security":
        return (<path d="M118 78 l6 6 -6 6 -6 -6 6 -6" fill="#60a5fa" />);
      case "fact":
        return (<circle cx="124" cy="86" r="5" fill="#eab308" />);
      case "stock":
        return (<>
          <path d="M40 120 l20 -20 l12 12 l16 -16" stroke="#34d399" strokeWidth="3" fill="none" />
          <path d="M88 96 l0 -12 l12 0" stroke="#34d399" strokeWidth="3" fill="none" />
        </>);
      case "crypto":
        return (<path d="M120 96 l6 10 l-6 10 l-6 -10 z" fill="#a78bfa" />);
      case "vigilante":
        return (<path d="M46 92 h20 l6 10 h-26 z" fill="#f472b6" />);
      case "scrapsmith":
        return (<rect x="112" y="98" width="12" height="12" fill="#9ca3af" />);
      case "ideatank":
        return (<circle cx="120" cy="76" r="6" fill="#f59e0b" />);
      default:
        return null;
    }
  };

  return (
    <div className="mascot-fixed">
      <div className="relative mascot-wrap" aria-hidden="true">
        {/* Bubbles */}
        <div className="mascot-bubbles">
          <div key={idx} className="bubble">{msgs[idx]}</div>
        </div>

        {/* Tornado with tie */}
        <svg className="mascot-svg" viewBox="0 0 160 160" role="img" aria-label="Tornado mascot">
          <defs>
            <linearGradient id="twirl" x1="0" y1="0" x2="1" y2="1">
              <stop offset="0%" stopColor="rgba(255,255,255,0.95)" />
              <stop offset="100%" stopColor="rgba(255,255,255,0.35)" />
            </linearGradient>
            <filter id="softGlow">
              <feGaussianBlur stdDeviation="1.4" result="b" />
              <feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
          </defs>

          {/* face */}
          <circle cx="68" cy="58" r="5.5" fill="white" />
          <circle cx="92" cy="58" r="5.5" fill="white" />
          <circle cx="68" cy="58" r="2.2" fill="#0f1113" />
          <circle cx="92" cy="58" r="2.2" fill="#0f1113" />
          <path d="M66 72 Q80 78 94 72" stroke="white" strokeWidth="2" fill="none" opacity="0.85" vectorEffect="non-scaling-stroke"/>

          {/* tie */}
          <path d="M80 82 l6 8 l-6 22 l-6 -22 z" fill="#ef4444" />
          <rect x="76" y="78" width="8" height="6" rx="2" fill="#ef4444" />

          {/* swirl */}
          <g filter="url(#softGlow)" stroke="url(#twirl)" fill="none" strokeLinecap="round">
            <path d="M30 48 C60 38, 100 38, 130 48" strokeWidth="3" vectorEffect="non-scaling-stroke"/>
            <path d="M24 70 C56 60, 104 60, 136 70" strokeWidth="3" vectorEffect="non-scaling-stroke"/>
            <path d="M20 92 C56 84, 108 84, 140 92" strokeWidth="3" vectorEffect="non-scaling-stroke"/>
            <path d="M34 114 C66 108, 94 108, 126 114" strokeWidth="3" vectorEffect="non-scaling-stroke"/>
            <path d="M48 130 C70 128, 86 128, 112 130" strokeWidth="2.5" vectorEffect="non-scaling-stroke"/>
          </g>

          {/* outfit */}
          {accessory(variant)}
        </svg>
      </div>
    </div>
  );
}
