def _read_pdf(path: Path) -> str:
    """Read PDF files using PyPDF2."""
    try:
        import PyPDF2
    except ImportError:
        logger.error("PyPDF2 not installed. Please run: pip install PyPDF2")
        return ""

    text_chunks = []
    try:
        with open(path, "rb") as f:
            reader = PyPDF2.PdfReader(f)
            for page in reader.pages:
                text_chunks.append(page.extract_text() or "")
        return "\n".join(text_chunks)
    except Exception as e:
        logger.error(f"Failed to read PDF {path}: {e}")
        return ""

def _read_docx(path: Path) -> str:
    """Read DOCX files using python-docx."""
    try:
        import docx
    except ImportError:
        logger.error("python-docx not installed. Please run: pip install python-docx")
        return ""

    text_chunks = []
    try:
        doc = docx.Document(path)
        for para in doc.paragraphs:
            text_chunks.append(para.text)
        return "\n".join(text_chunks)
    except Exception as e:
        logger.error(f"Failed to read DOCX {path}: {e}")
        return ""

