# ---------- Optional readers (clean & minimal) ----------
from pathlib import Path

def _read_text(path: Path) -> str:
    try:
        return path.read_text(encoding="utf-8", errors="ignore")
    except Exception:
        return ""

def _read_docx(path: Path) -> str:
    try:
        import docx  # pip install python-docx
        doc = docx.Document(str(path))
        return "\n".join(p.text for p in doc.paragraphs)
    except Exception:
        return ""

def _read_pdf(path: Path) -> str:
    """
    Robust but simple: try pdfminer first (best for text PDFs),
    then fall back to PyPDF2 if pdfminer isn't available or returns nothing.
    No OCR here (kept minimal & dependency-light).
    """
    # 1) pdfminer.six
    try:
        from pdfminer.high_level import extract_text  # pip install pdfminer.six
        txt = extract_text(str(path)) or ""
        if txt.strip():
            return txt
    except Exception:
        pass

    # 2) PyPDF2
    try:
        import PyPDF2  # pip install PyPDF2
        out = []
        with open(path, "rb") as f:
            reader = PyPDF2.PdfReader(f)
            for page in reader.pages:
                out.append(page.extract_text() or "")
        return "\n".join(out).strip()
    except Exception:
        return ""

def read_file(path: Path) -> str:
    suf = path.suffix.lower()
    if suf == ".txt":
        return _read_text(path)
    if suf == ".docx":
        return _read_docx(path)
    if suf == ".pdf":
        return _read_pdf(path)
    return ""
