def make_tree(start_path, max_depth=4):
    tree_lines = []
    start_path = pathlib.Path(start_path)
    for root, dirs, files in os.walk(start_path):
        depth = len(pathlib.Path(root).relative_to(start_path).parts)
        if depth > max_depth:
            # prevent deep recursion in display
            continue
        indent = "  " * depth
        rel_root = str(pathlib.Path(root).relative_to(start_path))
        tree_lines.append(f"{indent}{'./' if rel_root == '.' else rel_root + '/'}")
        for d in sorted(dirs):
            if depth + 1 <= max_depth:
                tree_lines.append(f"{indent}  {d}/")
        for f in sorted(files):
            tree_lines.append(f"{indent}  {f}")
    return "\n".join(tree_lines)

