}
.cta:hover{ border-color:var(--bubble-accent); color:var(--bubble-accent); }

/* idle sway + action spin */
@keyframes idleSway {
  0%{ transform: translateY(0) rotate(0deg); }
  50%{ transform: translateY(-2px) rotate(-1.5deg); }
  100%{ transform: translateY(0) rotate(0deg); }
}
@keyframes actionSpin {
  0%{ transform: rotate(0deg) }
  100%{ transform: rotate(360deg) }
}

#tm.idle { animation: idleSway 3.4s ease-in-out infinite; }
#tm.action { animation: actionSpin .65s linear infinite; filter: url(#spinBlur); }
